mapper.select:
SELECT count(1) totalCount FROM ( SELECT A.NIP_LINK_MST_SEQ , A.PIF_SERIAL_IP , A.SANEALIAS , A.SAMSTIP , A.SAIFNAME , A.SALOCATIONCODE , A.SAOFFICESCODE , B.SLVL_NM AS SAOFFICESCODE_NM , A.SZNEALIAS , A.SZMSTIP , A.SZIFNAME , A.SZLOCATIONCODE , A.SZOFFICESCODE , C.SLVL_NM AS SZOFFICESCODE_NM , A.SCONNALIAS , A.SSAID , A.SLLNUM , A.DCREATE_DT , A.SCREATE_ID , A.DMODIFY_DT , A.SMODIFY_ID FROM MST.TB_IP_LINK_MST A , MST.TB_LVL_CD B , MST.TB_LVL_CD C WHERE 1=1 AND B.SLVL_CD(+) = A.SAOFFICESCODE AND C.SLVL_CD(+) = A.SZOFFICESCODE
AND (A.SAOFFICESCODE IN ( SELECT SLOFFICECODE FROM MST.TB_LVL_SUB_CD WHERE SLVL_CD IN (SELECT SSVC_OBJ_CD FROM MST.TB_LVL_MST WHERE 1=1 AND NLVL_MST_SEQ IN
#{item.nlvlSeq}
)) OR A.SZOFFICESCODE IN ( SELECT SLOFFICECODE FROM MST.TB_LVL_SUB_CD WHERE SLVL_CD IN (SELECT SSVC_OBJ_CD FROM MST.TB_LVL_MST WHERE 1=1 AND NLVL_MST_SEQ IN
#{item.nlvlSeq}
)))
AND (( MST.FN_IP_TO_NUMBER(A.PIF_SERIAL_IP, 'START') >= (SELECT BIF.UF_SEARCH_IP_TO_NUMBER(#{searchWrd}, 'Y') FROM DUAL) AND MST.FN_IP_TO_NUMBER(A.PIF_SERIAL_IP, 'END') <= (SELECT BIF.UF_SEARCH_IP_TO_NUMBER(#{searchWrd}, 'N') FROM DUAL) ) OR ( MST.FN_IP_TO_NUMBER(A.PIF_SERIAL_IP, 'START') <= (SELECT BIF.UF_SEARCH_IP_TO_NUMBER(#{searchWrd}, 'Y') FROM DUAL) AND MST.FN_IP_TO_NUMBER(A.PIF_SERIAL_IP, 'END') >= (SELECT BIF.UF_SEARCH_IP_TO_NUMBER(#{searchWrd}, 'N') FROM DUAL) ) )
AND (A.SAOFFICESCODE = #{srssofficescode, jdbcType=CHAR} OR A.SZOFFICESCODE = #{srssofficescode, jdbcType=CHAR})
AND (A.SANEALIAS ILIKE '%' || #{smodelNm, jdbcType=VARCHAR} || '%' OR A.SZNEALIAS ILIKE '%' || #{smodelNm, jdbcType=VARCHAR} || '%')
AND (A.SAIFNAME ILIKE '%' || #{sifNm, jdbcType=VARCHAR} || '%' OR A.SZIFNAME ILIKE '%' || #{sifNm, jdbcType=VARCHAR} || '%')
AND A.SSAID ILIKE '%' || #{ssaid, jdbcType=VARCHAR} || '%'
AND A.SLLNUM ILIKE '%' || #{sllnum, jdbcType=VARCHAR} || '%'
AND A.SCONNALIAS ILIKE '%' || #{sconnalias, jdbcType=VARCHAR} || '%'
)

SELECT A.CODE AS SRSSOFFICESCODE , A.NAME AS SRSSOFFICESNM FROM ( SELECT A.SAOFFICESCODE AS code , B.SLVL_NM as name FROM MST.TB_IP_LINK_MST A , MST.TB_LVL_CD B WHERE 1=1 AND A.SAOFFICESCODE = B.SLVL_CD(+) AND A.SAOFFICESCODE IS NOT NULL
AND A.SAOFFICESCODE IN ( SELECT SSVC_OFFICE_CD FROM MST.TB_LVL_ROLE_SUB WHERE SSVC_OBJ_CD IN (SELECT SSVC_OBJ_CD FROM MST.TB_LVL_MST WHERE 1=1 AND NLVL_MST_SEQ IN
#{item.nlvlSeq}
))
GROUP BY A.SAOFFICESCODE, B.SLVL_NM UNION SELECT A.SZOFFICESCODE AS code , B.SLVL_NM as name FROM MST.TB_IP_LINK_MST A , MST.TB_LVL_CD B WHERE 1=1 AND A.SZOFFICESCODE = B.SLVL_CD(+) AND A.SZOFFICESCODE IS NOT NULL
AND A.SZOFFICESCODE IN ( SELECT SSVC_OFFICE_CD FROM MST.TB_LVL_ROLE_SUB WHERE SSVC_OBJ_CD IN (SELECT SSVC_OBJ_CD FROM MST.TB_LVL_MST WHERE 1=1 AND NLVL_MST_SEQ IN
#{item.nlvlSeq}
))
GROUP BY A.SZOFFICESCODE, B.SLVL_NM ) A WHERE A.NAME IS NOT NULL ORDER BY A.NAME

SELECT A.CODE , A.NAME FROM ( SELECT A.SAOFFICESCODE AS code , B.SLVL_NM as name FROM MST.TB_IP_LINK_MST A , MST.TB_LVL_CD B WHERE 1=1 AND A.SAOFFICESCODE = B.SLVL_CD(+) AND A.SAOFFICESCODE IS NOT NULL
AND A.SAOFFICESCODE IN ( SELECT SSVC_OFFICE_CD FROM MST.TB_LVL_ROLE_SUB WHERE SSVC_OBJ_CD IN (SELECT SSVC_OBJ_CD FROM MST.TB_LVL_MST WHERE 1=1 AND NLVL_MST_SEQ IN
#{item.nlvlSeq}
))
GROUP BY A.SAOFFICESCODE, B.SLVL_NM UNION SELECT A.SZOFFICESCODE AS code , B.SLVL_NM as name FROM MST.TB_IP_LINK_MST A , MST.TB_LVL_CD B WHERE 1=1 AND A.SZOFFICESCODE = B.SLVL_CD(+) AND A.SZOFFICESCODE IS NOT NULL
AND A.SZOFFICESCODE IN ( SELECT SSVC_OFFICE_CD FROM MST.TB_LVL_ROLE_SUB WHERE SSVC_OBJ_CD IN (SELECT SSVC_OBJ_CD FROM MST.TB_LVL_MST WHERE 1=1 AND NLVL_MST_SEQ IN
#{item.nlvlSeq}
))
GROUP BY A.SZOFFICESCODE, B.SLVL_NM ) A WHERE A.NAME IS NOT NULL ORDER BY A.NAME

mapper.insert:
INSERT INTO MST.TB_IP_LINK_MST 
(
	PIF_SERIAL_IP
	, SANEALIAS
	, SAMSTIP
	, SAIFNAME
	, SALOCATIONCODE
	, SAOFFICESCODE
	, SZNEALIAS
	, SZMSTIP
	, SZIFNAME
	, SZLOCATIONCODE
	, SZOFFICESCODE
	, SCONNALIAS
	, SSAID
	, SLLNUM
	, SCREATE_ID
	, SMODIFY_ID
	, DCREATE_DT
)
VALUES 
(
	#{pifSerialIp, javaType=Object, jdbcType=OTHER, typeHandler=com.kt.ipms.legacy.cmn.typehandler.CIDRTypeHandler}
	, #{sanealias, jdbcType=VARCHAR}
	, #{samstip, jdbcType=VARCHAR}
	, #{saifname, jdbcType=VARCHAR}
	, #{salocationcode, jdbcType=VARCHAR}
	, #{saofficescode, jdbcType=VARCHAR}
	, #{sznealias, jdbcType=VARCHAR}
	, #{szmstip, jdbcType=VARCHAR}
	, #{szifname, jdbcType=VARCHAR}
	, #{szlocationcode, jdbcType=VARCHAR}
	, #{szofficescode, jdbcType=VARCHAR}
	, #{sconnalias, jdbcType=VARCHAR}
	, #{ssaid, jdbcType=VARCHAR}
	, #{sllnum, jdbcType=VARCHAR}
	, #{smodifyId, jdbcType=VARCHAR}
	, #{smodifyId, jdbcType=VARCHAR}
	, SYSDATE
)

mapper.update:
UPDATE MST.TB_IP_LINK_MST A SET
	A.DMODIFY_DT = SYSDATE
	, A.SMODIFY_ID = #{smodifyId, jdbcType=VARCHAR}
	, A.SANEALIAS = #{sanealias, jdbcType=VARCHAR}
	, A.SAMSTIP = #{samstip, jdbcType=VARCHAR}
	, A.SAIFNAME = #{saifname, jdbcType=VARCHAR}
	, A.SALOCATIONCODE = #{salocationcode, jdbcType=VARCHAR}
	, A.SAOFFICESCODE = #{saofficescode, jdbcType=VARCHAR}
	, A.SZNEALIAS = #{sznealias, jdbcType=VARCHAR}
	, A.SZMSTIP = #{szmstip, jdbcType=VARCHAR}
	, A.SZIFNAME = #{szifname, jdbcType=VARCHAR}
	, A.SZLOCATIONCODE = #{szlocationcode, jdbcType=VARCHAR}
	, A.SZOFFICESCODE = #{szofficescode, jdbcType=VARCHAR}
	, A.SCONNALIAS = #{sconnalias, jdbcType=VARCHAR}
	, A.SSAID = #{ssaid, jdbcType=VARCHAR}
	, A.SLLNUM = #{sllnum, jdbcType=VARCHAR}
WHERE 
	A.NIP_LINK_MST_SEQ = #{nipLinkMstSeq, jdbcType=BIGINT}
